package com.taskflow.service;

import com.taskflow.dto.TaskPageResponse;
import com.taskflow.dto.TaskRequest;
import com.taskflow.dto.TaskResponse;
import com.taskflow.entity.Task;
import com.taskflow.repository.TaskRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageImpl;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;

import java.time.LocalDateTime;
import java.util.Collections;
import java.util.List;
import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.ArgumentMatchers.isNull;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class TaskServiceTest {

    @Mock
    private TaskRepository taskRepository;

    @InjectMocks
    private TaskService taskService;

    private Task sampleTask;
    private TaskRequest sampleRequest;

    @BeforeEach
    void setUp() {
        sampleTask = new Task();
        sampleTask.setId(1L);
        sampleTask.setTitle("Test Task");
        sampleTask.setDescription("Test Description");
        sampleTask.setPriority(Task.Priority.MEDIUM);
        sampleTask.setStatus(Task.TaskStatus.TODO);
        sampleTask.setCreatedBy(10L);
        sampleTask.setCreatedAt(LocalDateTime.now());
        sampleTask.setDeleted(false);

        sampleRequest = new TaskRequest();
        sampleRequest.setTitle("Test Task");
        sampleRequest.setDescription("Test Description");
        sampleRequest.setPriority(Task.Priority.HIGH);
    }

    // ========== createTask ==========

    @Nested
    class CreateTask {

        // AC1: POST /api/tasks returns 201 with TaskResponse
        @Test
        void shouldCreateTaskAndReturnResponse() {
            when(taskRepository.save(any(Task.class))).thenReturn(sampleTask);

            TaskResponse response = taskService.createTask(10L, sampleRequest);

            assertNotNull(response);
            assertEquals(1L, response.getId());
            assertEquals("Test Task", response.getTitle());
            assertEquals("Test Description", response.getDescription());
            assertEquals(Task.TaskStatus.TODO, response.getStatus());
            assertEquals(10L, response.getCreatedBy());
        }

        // AC1: should set createdBy from userId parameter
        @Test
        void shouldSetCreatedByFromUserId() {
            when(taskRepository.save(any(Task.class))).thenReturn(sampleTask);

            taskService.createTask(10L, sampleRequest);

            ArgumentCaptor<Task> captor = ArgumentCaptor.forClass(Task.class);
            verify(taskRepository).save(captor.capture());
            assertEquals(10L, captor.getValue().getCreatedBy());
        }

        // AC2: default priority is MEDIUM when not specified
        @Test
        void shouldDefaultPriorityToMedium_whenNotSpecified() {
            sampleRequest.setPriority(null);
            Task savedTask = new Task();
            savedTask.setId(2L);
            savedTask.setTitle("No Priority");
            savedTask.setPriority(Task.Priority.MEDIUM);
            savedTask.setStatus(Task.TaskStatus.TODO);
            savedTask.setCreatedBy(10L);
            savedTask.setCreatedAt(LocalDateTime.now());

            when(taskRepository.save(any(Task.class))).thenReturn(savedTask);

            TaskResponse response = taskService.createTask(10L, sampleRequest);

            assertEquals(Task.Priority.MEDIUM, response.getPriority());
        }

        // AC2: should respect explicit priority when specified
        @Test
        void shouldUseExplicitPriority_whenSpecified() {
            sampleRequest.setPriority(Task.Priority.HIGH);
            Task savedTask = new Task();
            savedTask.setId(3L);
            savedTask.setTitle("Test Task");
            savedTask.setPriority(Task.Priority.HIGH);
            savedTask.setStatus(Task.TaskStatus.TODO);
            savedTask.setCreatedBy(10L);
            savedTask.setCreatedAt(LocalDateTime.now());

            when(taskRepository.save(any(Task.class))).thenReturn(savedTask);

            TaskResponse response = taskService.createTask(10L, sampleRequest);

            assertEquals(Task.Priority.HIGH, response.getPriority());
        }

        // AC1: new task should always start with status TODO
        @Test
        void shouldSetStatusToTodo() {
            when(taskRepository.save(any(Task.class))).thenReturn(sampleTask);

            taskService.createTask(10L, sampleRequest);

            ArgumentCaptor<Task> captor = ArgumentCaptor.forClass(Task.class);
            verify(taskRepository).save(captor.capture());
            assertEquals(Task.TaskStatus.TODO, captor.getValue().getStatus());
        }

        // should pass title and description to saved entity
        @Test
        void shouldSetTitleAndDescription() {
            when(taskRepository.save(any(Task.class))).thenReturn(sampleTask);

            taskService.createTask(10L, sampleRequest);

            ArgumentCaptor<Task> captor = ArgumentCaptor.forClass(Task.class);
            verify(taskRepository).save(captor.capture());
            assertEquals("Test Task", captor.getValue().getTitle());
            assertEquals("Test Description", captor.getValue().getDescription());
        }
    }

    // ========== getTask ==========

    @Nested
    class GetTask {

        // AC4: GET /api/tasks/{id} returns 200 with TaskResponse
        @Test
        void shouldReturnTask_whenFound() {
            when(taskRepository.findByIdAndDeletedFalse(1L)).thenReturn(Optional.of(sampleTask));

            TaskResponse response = taskService.getTask(1L);

            assertNotNull(response);
            assertEquals(1L, response.getId());
            assertEquals("Test Task", response.getTitle());
        }

        // AC5: should throw when task not found
        @Test
        void shouldThrow_whenNotFound() {
            when(taskRepository.findByIdAndDeletedFalse(999L)).thenReturn(Optional.empty());

            assertThrows(RuntimeException.class, () -> taskService.getTask(999L));
        }

        // AC9: should throw when task is soft-deleted (findByIdAndDeletedFalse returns empty)
        @Test
        void shouldThrow_whenSoftDeleted() {
            when(taskRepository.findByIdAndDeletedFalse(1L)).thenReturn(Optional.empty());

            assertThrows(RuntimeException.class, () -> taskService.getTask(1L));
        }

        // should map all fields in response correctly
        @Test
        void shouldMapAllResponseFields() {
            sampleTask.setUpdatedAt(LocalDateTime.of(2026, 3, 6, 12, 0));
            when(taskRepository.findByIdAndDeletedFalse(1L)).thenReturn(Optional.of(sampleTask));

            TaskResponse response = taskService.getTask(1L);

            assertEquals(sampleTask.getId(), response.getId());
            assertEquals(sampleTask.getTitle(), response.getTitle());
            assertEquals(sampleTask.getDescription(), response.getDescription());
            assertEquals(sampleTask.getPriority(), response.getPriority());
            assertEquals(sampleTask.getStatus(), response.getStatus());
            assertEquals(sampleTask.getCreatedBy(), response.getCreatedBy());
            assertEquals(sampleTask.getCreatedAt(), response.getCreatedAt());
            assertEquals(sampleTask.getUpdatedAt(), response.getUpdatedAt());
        }
    }

    // ========== updateTask ==========

    @Nested
    class UpdateTask {

        // AC6: PUT /api/tasks/{id} updates and returns 200
        @Test
        void shouldUpdateAndReturn() {
            TaskRequest updateReq = new TaskRequest();
            updateReq.setTitle("Updated Title");
            updateReq.setDescription("Updated Desc");
            updateReq.setPriority(Task.Priority.LOW);

            Task updatedTask = new Task();
            updatedTask.setId(1L);
            updatedTask.setTitle("Updated Title");
            updatedTask.setDescription("Updated Desc");
            updatedTask.setPriority(Task.Priority.LOW);
            updatedTask.setStatus(Task.TaskStatus.TODO);
            updatedTask.setCreatedBy(10L);
            updatedTask.setCreatedAt(LocalDateTime.now());

            when(taskRepository.findByIdAndDeletedFalse(1L)).thenReturn(Optional.of(sampleTask));
            when(taskRepository.save(any(Task.class))).thenReturn(updatedTask);

            TaskResponse response = taskService.updateTask(1L, updateReq);

            assertEquals("Updated Title", response.getTitle());
            assertEquals("Updated Desc", response.getDescription());
            assertEquals(Task.Priority.LOW, response.getPriority());
        }

        // AC6: should throw 404 when task not found
        @Test
        void shouldThrow_whenTaskNotFound() {
            when(taskRepository.findByIdAndDeletedFalse(999L)).thenReturn(Optional.empty());

            TaskRequest updateReq = new TaskRequest();
            updateReq.setTitle("New Title");

            assertThrows(RuntimeException.class, () -> taskService.updateTask(999L, updateReq));
        }

        // should set updatedAt on update
        @Test
        void shouldSetUpdatedAt() {
            TaskRequest updateReq = new TaskRequest();
            updateReq.setTitle("Updated Title");

            when(taskRepository.findByIdAndDeletedFalse(1L)).thenReturn(Optional.of(sampleTask));
            when(taskRepository.save(any(Task.class))).thenAnswer(inv -> inv.getArgument(0));

            taskService.updateTask(1L, updateReq);

            ArgumentCaptor<Task> captor = ArgumentCaptor.forClass(Task.class);
            verify(taskRepository).save(captor.capture());
            assertNotNull(captor.getValue().getUpdatedAt());
        }

        // should not change createdBy or status
        @Test
        void shouldNotChangeCreatedByOrStatus() {
            TaskRequest updateReq = new TaskRequest();
            updateReq.setTitle("Updated Title");
            updateReq.setDescription("Updated Desc");
            updateReq.setPriority(Task.Priority.LOW);

            when(taskRepository.findByIdAndDeletedFalse(1L)).thenReturn(Optional.of(sampleTask));
            when(taskRepository.save(any(Task.class))).thenAnswer(inv -> inv.getArgument(0));

            taskService.updateTask(1L, updateReq);

            ArgumentCaptor<Task> captor = ArgumentCaptor.forClass(Task.class);
            verify(taskRepository).save(captor.capture());
            assertEquals(10L, captor.getValue().getCreatedBy());
            assertEquals(Task.TaskStatus.TODO, captor.getValue().getStatus());
        }
    }

    // ========== deleteTask ==========

    @Nested
    class DeleteTask {

        // AC7: DELETE /api/tasks/{id} soft deletes, returns 204
        @Test
        void shouldSoftDelete() {
            when(taskRepository.findByIdAndDeletedFalse(1L)).thenReturn(Optional.of(sampleTask));
            when(taskRepository.save(any(Task.class))).thenAnswer(inv -> inv.getArgument(0));

            taskService.deleteTask(1L);

            ArgumentCaptor<Task> captor = ArgumentCaptor.forClass(Task.class);
            verify(taskRepository).save(captor.capture());
            assertTrue(captor.getValue().isDeleted());
        }

        // AC7: should throw 404 when task not found
        @Test
        void shouldThrow_whenTaskNotFound() {
            when(taskRepository.findByIdAndDeletedFalse(999L)).thenReturn(Optional.empty());

            assertThrows(RuntimeException.class, () -> taskService.deleteTask(999L));
        }

        // should not hard delete from database
        @Test
        void shouldNotHardDelete() {
            when(taskRepository.findByIdAndDeletedFalse(1L)).thenReturn(Optional.of(sampleTask));
            when(taskRepository.save(any(Task.class))).thenAnswer(inv -> inv.getArgument(0));

            taskService.deleteTask(1L);

            verify(taskRepository, never()).delete(any());
            verify(taskRepository, never()).deleteById(any());
        }
    }

    // ========== listTasks ==========

    @Nested
    class ListTasks {

        // AC10: list with pagination returns TaskPageResponse
        @Test
        void shouldReturnPageResponse() {
            Page<Task> page = new PageImpl<>(List.of(sampleTask), PageRequest.of(0, 20), 1);
            when(taskRepository.findByFilters(isNull(), isNull(), isNull(), any(Pageable.class)))
                    .thenReturn(page);

            TaskPageResponse response = taskService.listTasks(null, null, null, PageRequest.of(0, 20));

            assertNotNull(response);
            assertEquals(1, response.getContent().size());
            assertEquals(0, response.getPage());
            assertEquals(20, response.getSize());
            assertEquals(1, response.getTotalElements());
            assertEquals(1, response.getTotalPages());
        }

        // AC11: keyword filter should pass to repository
        @Test
        void shouldPassKeywordToRepository() {
            Page<Task> page = new PageImpl<>(Collections.emptyList(), PageRequest.of(0, 20), 0);
            when(taskRepository.findByFilters(eq("test"), isNull(), isNull(), any(Pageable.class)))
                    .thenReturn(page);

            taskService.listTasks("test", null, null, PageRequest.of(0, 20));

            verify(taskRepository).findByFilters(eq("test"), isNull(), isNull(), any(Pageable.class));
        }

        // AC12: priority filter should pass to repository
        @Test
        void shouldPassPriorityFilterToRepository() {
            Page<Task> page = new PageImpl<>(Collections.emptyList(), PageRequest.of(0, 20), 0);
            when(taskRepository.findByFilters(isNull(), eq(Task.Priority.HIGH), isNull(), any(Pageable.class)))
                    .thenReturn(page);

            taskService.listTasks(null, Task.Priority.HIGH, null, PageRequest.of(0, 20));

            verify(taskRepository).findByFilters(isNull(), eq(Task.Priority.HIGH), isNull(), any(Pageable.class));
        }

        // status filter should pass to repository
        @Test
        void shouldPassStatusFilterToRepository() {
            Page<Task> page = new PageImpl<>(Collections.emptyList(), PageRequest.of(0, 20), 0);
            when(taskRepository.findByFilters(isNull(), isNull(), eq(Task.TaskStatus.TODO), any(Pageable.class)))
                    .thenReturn(page);

            taskService.listTasks(null, null, Task.TaskStatus.TODO, PageRequest.of(0, 20));

            verify(taskRepository).findByFilters(isNull(), isNull(), eq(Task.TaskStatus.TODO), any(Pageable.class));
        }

        // combined filters
        @Test
        void shouldPassAllFiltersToRepository() {
            Page<Task> page = new PageImpl<>(Collections.emptyList(), PageRequest.of(0, 20), 0);
            when(taskRepository.findByFilters(eq("key"), eq(Task.Priority.LOW), eq(Task.TaskStatus.DONE), any(Pageable.class)))
                    .thenReturn(page);

            taskService.listTasks("key", Task.Priority.LOW, Task.TaskStatus.DONE, PageRequest.of(0, 20));

            verify(taskRepository).findByFilters(eq("key"), eq(Task.Priority.LOW), eq(Task.TaskStatus.DONE), any(Pageable.class));
        }

        // empty list
        @Test
        void shouldReturnEmptyPage_whenNoTasks() {
            Page<Task> page = new PageImpl<>(Collections.emptyList(), PageRequest.of(0, 20), 0);
            when(taskRepository.findByFilters(isNull(), isNull(), isNull(), any(Pageable.class)))
                    .thenReturn(page);

            TaskPageResponse response = taskService.listTasks(null, null, null, PageRequest.of(0, 20));

            assertEquals(0, response.getContent().size());
            assertEquals(0, response.getTotalElements());
        }

        // AC8: soft-deleted tasks are excluded (repo query already filters)
        @Test
        void shouldOnlyReturnNonDeletedTasks() {
            Task activeTask = new Task();
            activeTask.setId(1L);
            activeTask.setTitle("Active");
            activeTask.setPriority(Task.Priority.MEDIUM);
            activeTask.setStatus(Task.TaskStatus.TODO);
            activeTask.setCreatedBy(10L);
            activeTask.setCreatedAt(LocalDateTime.now());
            activeTask.setDeleted(false);

            Page<Task> page = new PageImpl<>(List.of(activeTask), PageRequest.of(0, 20), 1);
            when(taskRepository.findByFilters(isNull(), isNull(), isNull(), any(Pageable.class)))
                    .thenReturn(page);

            TaskPageResponse response = taskService.listTasks(null, null, null, PageRequest.of(0, 20));

            assertEquals(1, response.getContent().size());
            assertEquals("Active", response.getContent().get(0).getTitle());
        }
    }
}

