    // ========== Helper Methods ==========

    private String taskJson(String title, String description, String priority) throws Exception {
        StringBuilder sb = new StringBuilder("{");
        sb.append("\"title\":\"").append(title).append("\"");
        if (description != null) {
            sb.append(",\"description\":\"").append(description).append("\"");
        }
        if (priority != null) {
            sb.append(",\"priority\":\"").append(priority).append("\"");
        }
        sb.append("}");
        return sb.toString();
    }

    private MvcResult createTaskAndReturn(String title, String description, String priority) throws Exception {
        return mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(taskJson(title, description, priority)))
                .andExpect(status().isCreated())
                .andReturn();
    }

