                            .param("page", "0")
                            .param("size", "2")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.content", hasSize(2)))
                    .andExpect(jsonPath("$.page").value(0))
                    .andExpect(jsonPath("$.size").value(2))
                    .andExpect(jsonPath("$.totalElements").value(3))
                    .andExpect(jsonPath("$.totalPages").value(2));
        }

        // AC13: second page
        @Test
        void shouldReturnSecondPage() throws Exception {
            createTaskGetId("Task 1", "Desc", null);
            createTaskGetId("Task 2", "Desc", null);
            createTaskGetId("Task 3", "Desc", null);

            mockMvc.perform(get("/api/tasks")
                            .param("page", "1")
                            .param("size", "2")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.content", hasSize(1)))
                    .andExpect(jsonPath("$.page").value(1));
        }
    }

    // =============================================
    // Auth (AC14)
    // =============================================

    @Nested
    class AuthRequired {

        // AC14: no token returns 401 for all task endpoints
        @Test
        void shouldReturn401_createWithoutToken() throws Exception {
            mockMvc.perform(post("/api/tasks")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"Test\"}"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        void shouldReturn401_getWithoutToken() throws Exception {
            mockMvc.perform(get("/api/tasks/1"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        void shouldReturn401_updateWithoutToken() throws Exception {
            mockMvc.perform(put("/api/tasks/1")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"Test\"}"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        void shouldReturn401_deleteWithoutToken() throws Exception {
            mockMvc.perform(delete("/api/tasks/1"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        void shouldReturn401_listWithoutToken() throws Exception {
            mockMvc.perform(get("/api/tasks"))
                    .andExpect(status().isUnauthorized());
        }

        // invalid token returns 401
        @Test
        void shouldReturn401_withInvalidToken() throws Exception {
            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer invalid-token"))
                    .andExpect(status().isUnauthorized());
        }
    }

    // =============================================
    // End-to-end CRUD flow
    // =============================================

    @Nested
    class EndToEndFlow {

        @Test
        void shouldCompleteCrudFlow() throws Exception {
            // Create
            MvcResult createResult = mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(taskJson("E2E Task", "E2E Desc", "HIGH")))
                    .andExpect(status().isCreated())
                    .andReturn();

            Long taskId = objectMapper.readTree(createResult.getResponse().getContentAsString())
                    .get("id").asLong();

            // Read
            mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.title").value("E2E Task"));

            // Update
            mockMvc.perform(put("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(taskJson("Updated E2E", "Updated Desc", "LOW")))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.title").value("Updated E2E"))
                    .andExpect(jsonPath("$.priority").value("LOW"));

            // Verify update persisted
            mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.title").value("Updated E2E"));

            // Delete
            mockMvc.perform(delete("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNoContent());

            // Verify deleted (404)
            mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNotFound());

            // Verify not in list
            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.content", hasSize(0)));
        }
    }
}

